pub fn block_read<T: Clone + Sized>(
    dev: &Arc<dyn BlockDevice>, block_id: usize, offset: usize
) -> T {
    let mut buf = [0u8; BLOCK_SZ];
    dev.read_block(block_id, &mut buf);
    unsafe { (&*(buf.as_ptr().add(offset) as *const T)).clone() }
}

